SELECT [Transfer Receipt Line].[Document No_], [Transfer Receipt Line].[Item Type], [Transfer Receipt Line].[Item No_], [Transfer Receipt Line].[Constant Variable Code], [Transfer Receipt Line].[Season Code], [Transfer Receipt Line].[Receipt Date], Sum(Val([NO_ OF PAIRS])) AS QTY, [Transfer Receipt Line].[Transfer Order No_], [Transfer Receipt Line].Description, [Transfer Receipt Header].Note, [Transfer Receipt Header].Typification
FROM [Transfer Receipt Line] INNER JOIN [Transfer Receipt Header] ON [Transfer Receipt Line].[Document No_] = [Transfer Receipt Header].No_
WHERE ((([Transfer Receipt Line].[Transfer-to Code])="PMAG" Or ([Transfer Receipt Line].[Transfer-to Code])="SPMAG" Or ([Transfer Receipt Line].[Transfer-to Code])="DBG"))
GROUP BY [Transfer Receipt Line].[Document No_], [Transfer Receipt Line].[Item Type], [Transfer Receipt Line].[Item No_], [Transfer Receipt Line].[Constant Variable Code], [Transfer Receipt Line].[Season Code], [Transfer Receipt Line].[Receipt Date], [Transfer Receipt Line].[Transfer Order No_], [Transfer Receipt Line].Description, [Transfer Receipt Header].Note, [Transfer Receipt Header].Typification
HAVING ((([Transfer Receipt Line].[Item Type])=19 Or ([Transfer Receipt Line].[Item Type])=20) AND (([Transfer Receipt Line].[Season Code])=[CODICE STAGIONE]) AND (([Transfer Receipt Header].Typification)="PRODUZIONE" Or ([Transfer Receipt Header].Typification)="produzione"));

